<script setup>
import { computed } from 'vue'

const props = defineProps({
  myId: String,
  players: {
    type: Object,
    default: () => ({})
  },
  validation: {
    type: Object,
    default: () => ({})
  },
  categories: {
    type: Array,
    default: () => []
  }
})

const emit = defineEmits(['finish', 'toggle'])

// Computado seguro para 'me'
const me = computed(() => {
  if (!props.players || !props.myId) return { name: '', answers: {} }
  return props.players[props.myId] || { name: '', answers: {} }
})

// Computado seguro para 'allPlayers'
const allPlayers = computed(() => {
  if (!props.players) return []
  const playerList = Object.values(props.players)
  return playerList.sort((a, b) => {
    if (a.id === props.myId) return -1
    if (b.id === props.myId) return 1
    return (a.name || '').localeCompare(b.name || '')
  })
})

const isWaiting = computed(() => me.value && me.value.readyToResults)

const toggle = (playerId, categoryId, pAnswers) => {
  if (isWaiting.value) return
  const word = pAnswers ? pAnswers[categoryId] : null
  if (!word || word.trim().length <= 1) return
  emit('toggle', { targetPlayerId: playerId, categoryId })
}

const finish = () => {
  if (isWaiting.value) return
  emit('finish')
}

const formatWord = (word) => word || '---'

const getIsValid = (pId, catId) => {
  // Triple check de seguridad para evitar el TypeError
  if (!props.validation) return false
  if (!props.validation[pId]) return false
  return !!props.validation[pId][catId]
}
</script>

<template>
  <div class="validator-view">
    <div class="bento-card table-card active-glow">
      <h2>Calificación Cruzada</h2>
      <p class="subtitle">Validación sincronizada. Los cambios se ven en tiempo real.</p>

      <div v-if="allPlayers.length > 0" class="validator-grid" :style="{ gridTemplateColumns: `1.5fr repeat(${allPlayers.length}, 1fr)` }">
        <!-- Encabezados -->
        <div class="grid-header">Categoría</div>
        <div class="grid-header" v-for="p in allPlayers" :key="p.id" :class="{ 'is-me': p.id === myId }">
          {{ p.name || 'Jugador' }} {{ p.id === myId ? '(Tú)' : '' }}
        </div>

        <!-- Filas de Categorías -->
        <template v-for="cat in categories" :key="cat.id">
          <div class="grid-cat">{{ cat.label }}</div>
          
          <div 
            v-for="p in allPlayers" 
            :key="p.id"
            class="grid-cell" 
            :class="{ 
              'valid-word': getIsValid(p.id, cat.id), 
              'invalid-word': !getIsValid(p.id, cat.id) && p.answers && (p.answers[cat.id] || '').trim().length > 1,
              'empty-word': !p.answers || !(p.answers[cat.id] || '').trim().length > 1,
              'clickable': !isWaiting && p.answers && (p.answers[cat.id] || '').trim().length > 1
            }"
            @click="toggle(p.id, cat.id, p.answers)"
          >
            <div class="cell-content">
              <span class="word-display">{{ p.answers ? formatWord(p.answers[cat.id]) : '---' }}</span>
              <div v-if="p.answers && (p.answers[cat.id] || '').trim().length > 1" class="check-wrapper">
                <input 
                  type="checkbox" 
                  :checked="getIsValid(p.id, cat.id)" 
                  class="real-check" 
                  @click.stop
                />
              </div>
            </div>
          </div>
        </template>
      </div>

      <div class="validator-footer">
        <p v-if="!isWaiting" class="hint">💡 Haz clic en cualquier palabra para cambiar su validez.</p>
        <button class="finish-btn" @click="finish" :disabled="isWaiting">
          {{ isWaiting ? 'ESPERANDO A OTROS JUGADORES...' : 'CONFIRMAR Y FINALIZAR' }}
        </button>
      </div>
    </div>
  </div>
</template>

